#include <bits/stdc++.h>
using namespace std;
int n,a[10005],b[10005],aa,bb;
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=0;i<n;i++){
		int x;
		cin>>x;
		if(x%2){
			a[aa++]=x;
		}else{
			b[bb++]=x;
		}
	}
	for(int i=0;i<aa;i++){
		cout<<a[i]<<" ";
	}
	cout<<"\n";
	for(int i=0;i<bb;i++){
		cout<<b[i]<<" ";
	}
	return 0;
}
